import{_ as a,o as d,c as r,ai as e}from"./chunks/framework.SowO7O0D.js";const p=JSON.parse('{"title":"第十三课：行业轮动","description":"","frontmatter":{},"headers":[],"relativePath":"guide/13-sector-rotation.md","filePath":"guide/13-sector-rotation.md","lastUpdated":0}'),o={name:"guide/13-sector-rotation.md"};function h(l,t,n,i,s,b){return d(),r("div",null,[...t[0]||(t[0]=[e('<h1 id="第十三课-行业轮动" tabindex="-1">第十三课：行业轮动 <a class="header-anchor" href="#第十三课-行业轮动" aria-label="Permalink to “第十三课：行业轮动”">​</a></h1><p>A股市场有一个规律：<strong>不同行业此起彼伏</strong>，资金像接力棒一样轮番炒作。</p><h2 id="一、什么是行业轮动" tabindex="-1">一、什么是行业轮动？ <a class="header-anchor" href="#一、什么是行业轮动" aria-label="Permalink to “一、什么是行业轮动？”">​</a></h2><p>不同行业会像&quot;接力棒&quot;一样，此起彼伏地表现好。</p><p>资金会从涨多的行业撤出，流入估值低的行业，形成<strong>轮动</strong>。</p><h2 id="二、美林投资时钟" tabindex="-1">二、美林投资时钟 <a class="header-anchor" href="#二、美林投资时钟" aria-label="Permalink to “二、美林投资时钟”">​</a></h2><p>这是最经典的行业轮动理论，把经济周期分为4个阶段：</p><table tabindex="0"><thead><tr><th>阶段</th><th>经济状态</th><th>表现最好的资产</th></tr></thead><tbody><tr><td>🟢 复苏期</td><td>经济好转</td><td>股票</td></tr><tr><td>🔴 过热期</td><td>通胀上升</td><td>商品（黄金、石油等）</td></tr><tr><td>🟡 滞胀期</td><td>经济停滞+通胀</td><td>现金</td></tr><tr><td>🔵 衰退期</td><td>经济下滑</td><td>债券</td></tr></tbody></table><blockquote><p>💡 <strong>经济复苏买股票，经济过热买商品，经济滞胀持现金，经济衰退买债券。</strong></p></blockquote><h2 id="三、a股行业轮动规律" tabindex="-1">三、A股行业轮动规律 <a class="header-anchor" href="#三、a股行业轮动规律" aria-label="Permalink to “三、A股行业轮动规律”">​</a></h2><h3 id="牛市各阶段" tabindex="-1">牛市各阶段 <a class="header-anchor" href="#牛市各阶段" aria-label="Permalink to “牛市各阶段”">​</a></h3><table tabindex="0"><thead><tr><th>牛市阶段</th><th>表现最好的板块</th></tr></thead><tbody><tr><td>初期</td><td><strong>券商股</strong>（&quot;春江水暖鸭先知&quot;）</td></tr><tr><td>中期</td><td>消费、科技轮流表现</td></tr><tr><td>后期</td><td>银行、地产等蓝筹补涨</td></tr></tbody></table><h3 id="熊市-震荡市" tabindex="-1">熊市/震荡市 <a class="header-anchor" href="#熊市-震荡市" aria-label="Permalink to “熊市/震荡市”">​</a></h3><table tabindex="0"><thead><tr><th>市场环境</th><th>表现最好的板块</th></tr></thead><tbody><tr><td>熊市</td><td><strong>医药、消费</strong>（防御性板块）</td></tr><tr><td>震荡市</td><td>题材股、短线机会</td></tr></tbody></table><h2 id="四、如何把握热点轮动" tabindex="-1">四、如何把握热点轮动？ <a class="header-anchor" href="#四、如何把握热点轮动" aria-label="Permalink to “四、如何把握热点轮动？”">​</a></h2><h3 id="_1-看政策方向" tabindex="-1">1. 看政策方向 <a class="header-anchor" href="#_1-看政策方向" aria-label="Permalink to “1. 看政策方向”">​</a></h3><p>国家政策扶持什么，什么行业就容易表现。</p><blockquote><p>举例：国家鼓励新能源汽车 → 整车、电池、充电桩整个产业链涨</p></blockquote><h3 id="_2-看资金流向" tabindex="-1">2. 看资金流向 <a class="header-anchor" href="#_2-看资金流向" aria-label="Permalink to “2. 看资金流向”">​</a></h3><p>钱往哪里流，哪里就可能有机会。</p><blockquote><p>东方财富APP → 数据中心 → 行业资金流向</p></blockquote><h3 id="_3-看板块涨幅榜" tabindex="-1">3. 看板块涨幅榜 <a class="header-anchor" href="#_3-看板块涨幅榜" aria-label="Permalink to “3. 看板块涨幅榜”">​</a></h3><p>每天收盘后，看行业涨幅排名靠前的是什么。</p><h3 id="_4-不要追已经涨了很多的" tabindex="-1">4. 不要追已经涨了很多的 <a class="header-anchor" href="#_4-不要追已经涨了很多的" aria-label="Permalink to “4. 不要追已经涨了很多的”">​</a></h3><p>等散户都知道&quot;这个板块很热&quot;的时候，往往是主力出货的时候。</p><h2 id="五、概念题材炒作周期" tabindex="-1">五、概念题材炒作周期 <a class="header-anchor" href="#五、概念题材炒作周期" aria-label="Permalink to “五、概念题材炒作周期”">​</a></h2><p>题材炒作一般分为几个阶段：</p><table tabindex="0"><thead><tr><th>阶段</th><th>特征</th><th>散户该怎么做</th></tr></thead><tbody><tr><td>萌芽期</td><td>只有少数人知道</td><td>可以小仓位尝试</td></tr><tr><td>爆发期</td><td>连续涨停，开始扩散</td><td>谨慎，不建议追</td></tr><tr><td>高峰期</td><td>全民皆知，媒体热炒</td><td>⚠️ 绝对不要买</td></tr><tr><td>退潮期</td><td>开始连续跌停</td><td>跑都跑不掉</td></tr></tbody></table><blockquote><p>🚨 <strong>题材炒作是&quot;击鼓传花&quot;</strong>，最后接盘的人会亏得很惨。</p></blockquote><h2 id="六、行业配置建议" tabindex="-1">六、行业配置建议 <a class="header-anchor" href="#六、行业配置建议" aria-label="Permalink to “六、行业配置建议”">​</a></h2><p>对于新手，建议<strong>均衡配置</strong>：</p><table tabindex="0"><thead><tr><th>类型</th><th>比例</th><th>举例</th></tr></thead><tbody><tr><td>防御性</td><td>30%</td><td>医药、消费</td></tr><tr><td>成长性</td><td>30%</td><td>科技、新能源</td></tr><tr><td>价值型</td><td>30%</td><td>银行、蓝筹</td></tr><tr><td>现金</td><td>10%</td><td>等待机会</td></tr></tbody></table><h2 id="思考题" tabindex="-1">思考题 <a class="header-anchor" href="#思考题" aria-label="Permalink to “思考题”">​</a></h2><blockquote><p>现在是牛市中期，消费股涨了很多，但券商股还没怎么涨。你会怎么配置？</p></blockquote><hr><p><strong>下一课预告</strong>：理解了市场规律，下一课学习<strong>ETF基金</strong>——让小白也能轻松投资指数。</p>',36)])])}const _=a(o,[["render",h]]);export{p as __pageData,_ as default};
